import { useState } from "react";
import { TreeCanvas } from "../../components/tree/TreeCanvas";
import type { TreeNode } from "../../components/tree/types";
import { GraphToolbar, useGraphFilter, defaultGraphFilter } from "../../components/graph";
import { initialTree } from "./data";
import { treeConfig } from "./config";
import { useEdgeSurveyFlowTreeHandlers } from "./handlers";

/**
 * EdgeSurveyFlowTree — a fully-typed, self-contained tree with a search / sort /
 * filter toolbar above the canvas.
 *
 * Drop into any page:
 *   <EdgeSurveyFlowTree />
 *
 * To plug into a backend, edit the handlers in `./handlers.ts`. To remove the
 * toolbar, delete the `GraphToolbar`/`useGraphFilter` wiring below and set
 * `showToolbar: false` in `./config.ts`.
 */
export function EdgeSurveyFlowTree() {
  const [tree, setTree] = useState<TreeNode>(initialTree);
  const [filter, setFilter] = useState(defaultGraphFilter);
  const { handleNodeAdd, handleNodeUpdate, handleNodeRemove, handleNodeMove } = useEdgeSurveyFlowTreeHandlers();
  const { tree: filteredTree, matches, stats, allTags } = useGraphFilter(tree, filter);

  return (
    <div className="flex flex-col gap-2">
      <GraphToolbar
        filter={filter}
        onChange={setFilter}
        allTags={allTags}
        matched={stats.matched}
        total={stats.total}
      />
      <TreeCanvas
        config={treeConfig}
        tree={filter.mode === "hide" ? filteredTree : tree}
        onTreeChange={setTree}
        highlightIds={filter.mode === "dim" ? matches : undefined}
        onNodeAdd={handleNodeAdd}
        onNodeUpdate={handleNodeUpdate}
        onNodeRemove={handleNodeRemove}
        onNodeMove={handleNodeMove}
      />
    </div>
  );
}

import type { TreeCanvasConfig } from "../../components/tree/types";

/** Static configuration. All fields are typed and validated. */
export const treeConfig: TreeCanvasConfig = {
  "title": "NPS survey flow",
  "layout": "vertical",
  "editable": true,
  "draggable": true,
  "connector": "stepped",
  "panZoom": true,
  "background": "grid",
  "siblingGap": 24,
  "levelGap": 90,
  "minHeight": 480
};

import type { TreeNode } from "../../components/tree/types";

/** Initial tree data. Swap with your own backend fetch when wiring up production. */
export const initialTree: TreeNode = {
  "id": "q1",
  "label": "Did you use the product this week?",
  "meta": {
    "badge": "Q1",
    "color": "hsl(217 91% 60%)"
  },
  "children": [
    {
      "id": "q1-yes",
      "label": "How satisfied are you?",
      "meta": {
        "edgeLabel": "Yes"
      },
      "children": [
        {
          "id": "csat-high",
          "label": "Promoter",
          "meta": {
            "edgeLabel": "9–10",
            "color": "hsl(160 84% 39%)"
          }
        },
        {
          "id": "csat-mid",
          "label": "Passive",
          "meta": {
            "edgeLabel": "7–8",
            "color": "hsl(38 92% 50%)"
          }
        },
        {
          "id": "csat-low",
          "label": "Detractor",
          "meta": {
            "edgeLabel": "0–6",
            "color": "hsl(0 84% 60%)"
          }
        }
      ]
    },
    {
      "id": "q1-no",
      "label": "Why not?",
      "meta": {
        "edgeLabel": "No"
      },
      "children": [
        {
          "id": "why-time",
          "label": "No time",
          "meta": {
